      )
      expect(response.status).to eq(415)
      expect(response.body).to eq({ 'detail' => 'Unsupported charset \'utf-16\' for JSON. Only UTF-8 is supported.', 'status' => 415, 'title' => 'Unsupported Charset', 'type' => 'https://spikard.dev/errors/unsupported-charset' })
    end
  end

  describe 'POST /data' do
    it 'Content-Type header should be case-insensitive' do
      response = client.post('/data',
        json: { 'name' => 'test' },
        headers: { 'Content-Type' => 'APPLICATION/JSON' }
      )
      expect(response.status).to eq(201)
      expect(response.body).to eq({ 'name' => 'test' })
    end
  end

  describe 'POST /upload' do
    it 'Multipart content-type without boundary parameter should fail' do
      response = client.post('/upload',
        headers: { 'Content-Type' => 'multipart/form-data' }
      )
      expect(response.status).to eq(400)
      expect(response.body).to eq({ 'error' => 'multipart/form-data requires \'boundary\' parameter' })
    end
  end

  describe 'POST /data' do
    it 'text/plain content-type should be rejected when JSON is expected' do
      response = client.post('/data',
        json: '{"data": "value"}',
        headers: { 'Content-Type' => 'text/plain' }
      )
      expect(response.status).to eq(415)
      expect(response.body).to eq({ 'detail' => 'Unsupported media type', 'status' => 415, 'title' => 'Unsupported Media Type', 'type' => 'https://spikard.dev/errors/unsupported-media-type' })
    end
  end

  describe 'POST /api/v1/resource' do
    it 'Vendor-specific JSON content-type should be accepted' do
      response = client.post('/api/v1/resource',
        json: { 'data' => 'value' },
        headers: { 'Content-Type' => 'application/vnd.api+json' }
      )
      expect(response.status).to eq(201)
      expect(response.body).to eq({ 'data' => 'value' })
    end
  end

  describe 'POST /data' do
    it 'Content-Type with multiple parameters should be parsed correctly' do
      response = client.post('/data',
        json: { 'value' => 'test' },
        headers: { 'Content-Type' => 'application/json; charset=utf-8; boundary=something' }
      )
      expect(response.status).to eq(201)
      expect(response.body).to eq({ 'value' => 'test' })
    end
  end

  describe 'POST /data' do
    it 'Missing Content-Type header should default to JSON when body is present' do
      response = client.post('/data',
        json: { 'name' => 'test' }
      )
      expect(response.status).to eq(201)
      expect(response.body).to eq({ 'name' => 'test' })
    end
  end

  describe 'POST /data' do
    it 'Content-Length header mismatch with actual body size should fail' do
      response = client.post('/data',
        json: { 'value' => 'short' },
        headers: { 'Content-Type' => 'application/json', 'Content-Length' => '100' }
      )
      expect(response.status).to eq(400)
      expect(response.body).to eq({ 'detail' => 'Content-Length header does not match actual body size', 'status' => 400, 'title' => 'Content-Length header mismatch', 'type' => 'https://spikard.dev/errors/content-length-mismatch' })
    end
  end

  describe 'POST /items/' do
    it 'Tests rejection of unsupported content type' do
      response = client.post('/items/',
